export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "18:42。小野寺離開之後，房間裡的空氣鬆了一層。不是溫暖。是那種壓力源消失後、牆壁還沒來得及變回原色的鬆。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人回到桌邊。他把紀錄板翻到新的一頁。開始整理今天的物件確認紀錄。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他一邊核對，一邊把完成的項目念出來。像在讀清單。每一項之間停一下。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "正反面照片。完成。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "尺寸與重量。完成。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "刮痕位置。已標記。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "物件來源陳述。已記錄。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "預約頁裁切圖來源。已記錄。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "供應商技術說明。已記錄。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他念完最後一項，把筆放下。手指在桌面上敲了一下，像在確認所有欄位都填滿了。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他翻回前面。找到澪的陳述那一段。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "我讀回妳的陳述。有錯可以更正。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他開始念。速度比剛才慢。像在讓每一個字都有時間被檢查。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "預約頁清楚顯示 G07／12。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "鏡背部分筆畫與該代碼局部相符。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "妳沒有主張這一定是 TKS-SYNC 地址。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "妳沒有同意外部公司保存原件或裁切資料。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "小鏡子原件未被留置。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停下來。抬頭看她。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "這些是妳的陳述。有需要更正的嗎？", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有。", background: Background.Chapter_13_Ch13_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音很穩。比她感覺到的穩。這五條都是她說過的話。沒有一條被改寫。沒有一條被誇大。沒有一條把「局部相符」寫成「刻著」。沒有一條把「我沒有主張」寫成「我確認」。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我的話被原樣記下來了。這是我能確認的。我能確認的是我說過什麼。我不能確認的是他們會怎麼用它。", background: Background.Chapter_13_Ch13_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人點頭。在陳述紀錄的底部寫了一行字。她看見自己的名字被謄寫一次，旁邊是「陳述確認」和今天的日期。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他翻到另一頁。不是她的陳述。是內部補充報告的欄位。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "這部分不是妳的陳述。是警方的內部紀錄。我說明一下會寫什麼。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣變了。不是對證人說話的語氣。是對一個被允許在場聽見、但不被允許核定的人說話的語氣。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "TKS 供應商技術人員稱，G07／12 與 TKS-SYNC 公開地址表記方式相似。若依其產品語法，可讀為同步群 07、端點 12。來源、用途及刑事關聯未定。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他念完。沒有問她意見。沒有把這段遞給她簽名。這段不屬於她的陳述。它屬於警方的內部判斷。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我聽見了。這段會進案件資料。同步群 07、端點 12。和個體 12 放在同一個檔案裡。可是我拿不到副本。我無權核定警方最後怎麼評價它。我能做的只有——聽見。記住。知道它存在。", background: Background.Chapter_13_Ch13_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人把那一頁翻過去。她看不見後面寫了什麼。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有問。她知道問了也不會拿到。這是程序的邊界——她把自己的陳述放進去，程序把她的陳述還給她確認；但程序對供應商說法的評價，不屬於她能確認的範圍。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這是我選的。我選擇把 G07／12 放進官方程序。我選擇讓 TKS 知道這串代碼被看見了。代價是——接下來誰能讀到這段供應商說明，我不一定能掌握。它會在案件資料裡。它會被某個人看見。也許是對的人。也許不是。", background: Background.Chapter_13_Ch13_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人合上紀錄板。站起來。走到桌邊，拿起證物袋。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他打開袋子。把小鏡子取出來。放在桌面上。旁邊放了一張返還確認單。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警察", dialogue: "小鏡一件。外觀狀態如紀錄。拍照完成。未留置。未交付外部公司。19:15 返還。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把返還確認單推到她面前。上面有她的名字、物件描述、返還時間。底部有一欄簽名。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著那面鏡子。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它還是它。正面是鏡面。背面有那些刻痕。沒有新的標記。沒有被裝進另一個更大的袋子。沒有被改名叫「證物編號幾號」。它從程序裡走了一圈，回到她面前。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯你回來了。", background: Background.Chapter_13_Ch13_Act5_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她伸出手。把鏡子拿起來。掌心貼著背面。那些刻痕在她的皮膚上留下細微的凸起感。她把它放回小布套裡。放進背包。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她拿起筆。在返還確認單上簽名。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有拿到內部補充報告的副本。她只拿到這張單子。一張證明她的東西回到了她手裡的單子。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這就夠了。今天能拿到的，就這些。鏡子。返還確認。我的陳述被原樣記錄。供應商說法進了案件資料——我聽見了，但我拿不到。這是邊界。我選擇了這個邊界。我接受它。", background: Background.Chapter_13_Ch13_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:13。承辦人把紀錄板夾在腋下，帶她走向接待櫃台。", background: Background.Chapter_13_Ch13_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "接待櫃台。晚間的署裡人少了。走廊的燈光被調暗了一級，像在建築也要省電。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人在櫃台完成最後的返還程序。蓋章。時間戳。19:15。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪把返還確認單摺好，收進背包內層。和那個密封信封放在一起。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她正要轉身離開的時候，看見走廊盡頭有一個身影。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "深色西裝。舊皮鞋。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部從走廊那頭走過來。他沒有朝她走。他朝承辦人走。像他本來就要經過這裡，像他本來就在處理別的事。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在櫃台邊停了一下。對承辦人說了一句話。聲音不大，但走廊安靜，她聽見了。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "照片外部使用的任何新請求，都另立紀錄。", background: Background.Chapter_13_Ch13_Act5_S1, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "承辦人點頭。在另一份表單上記了一行。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部沒有看她。他說完那句話就繼續走了。皮鞋的聲音在走廊裡變遠。像一條線被拉過一個安靜的房間。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他沒有跟我說話。一句都沒有。他只對承辦人說了一句——照片外部使用的任何新請求，都另立紀錄。這句話不是對我說的。可是我聽見了。他在告訴承辦人：如果 TKS 再要那些裁切圖，不能直接給。要另立紀錄。要留下痕跡。要讓每一次外部接觸都有跡可查。", background: Background.Chapter_13_Ch13_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在接待櫃台邊。背包裡有小鏡子、返還確認單、密封信封。口袋裡有手機。手機裡有早上拍的備份照片。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我今天做了什麼？我把悠真的預約頁代碼放進警方程序。我把小鏡子放進警方程序。我讓一個 TKS 的工程師看見了 G07／12。他說它像同步產品的地址表記。他說如果照他們的系統讀，它是第七同步群、第十二端點。這段話現在在案件資料裡。", background: Background.Chapter_13_Ch13_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我也正式讓 TKS 知道了——這串代碼已經被看見了。不是在圖書館的文件套裡被看見。不是在家屬互助圈的影印紙上被看見。是在警署的物件確認室裡，被一個供應商工程師親眼看見。他回去之後會怎麼說？公司安全部門會不會發函？教育資料服務部會不會收到通知？我不知道。", background: Background.Chapter_13_Ch13_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走向署的出口。玻璃門外是夜晚的街道。路燈已經亮了。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我成功把清晰代碼和鏡背物證放進官方程序。這是我要的。可是放進去之後，它就不只屬於我了。它屬於案件資料。屬於承辦人的紀錄。屬於那份我聽見但拿不到的內部補充報告。屬於任何將來有權調閱這個檔案的人。", background: Background.Chapter_13_Ch13_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這是測試的代價。我測試了 TKS 的第一反應。代價是——資訊會外流。我不一定能掌握它流向哪裡。", background: Background.Chapter_13_Ch13_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她推開玻璃門。夜晚的空氣進來了。比署裡的空氣涼。比署裡的空氣有味道——街上的味道、排水溝的味道、遠處某家店的味道。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在署門口的階梯上。打開私人筆記。翻到那一頁。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三行字。她今天下午寫的。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "個體 12？", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "端點 12？", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "朝倉悠真。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著這三行。前兩行後面有問號。第三行沒有。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯個體 12。端點 12。兩套系統。兩個名字。一個是研究後台給他的。一個是警報產品語法給他的。都不是我給他的。我給他的名字在第三行。沒有問號。", background: Background.Chapter_13_Ch13_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她合上筆記本。放進背包。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "19:17。她走下階梯。手機螢幕亮了一下。一則提醒。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "20:00　兼職辦公室", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯二十點。辦公室。第三份備份要放進鎖櫃。然後——公開手冊。採購附件。舊公共文件。TKS-SYNC 的群與端。灣岸測試用了哪套系統。還有⋯⋯", background: Background.Chapter_13_Ch13_Act5_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有把那個「還有」想完。她把它留在那裡。像一個還沒有被翻開的頁碼。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走向車站。背包裡的小鏡子隨著步伐輕輕晃了一下。它在布套裡。在她身上。還屬於她。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "還屬於悠真。", background: Background.Chapter_13_Ch13_Act5_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是她今天唯一能確定的事。", background: Background.Chapter_13_Ch13_Act5_S1 },
];
